from __future__ import annotations

import csv
import os
import subprocess
import time
from pathlib import Path

# File paths and Configuration
# Get the directory where this Python file is located
BASE_DIR = Path(__file__).resolve().parent

# CSV file generated by the SDN controller
# Contains backend decisions made by the load balancer
DECISIONS_CSV = BASE_DIR / "decisions.csv"

# Output dataset used for ML training
DATASET_CSV = BASE_DIR / "dataset.csv"

# Virtual IP address of the load balancer
# Can be overridden using environment variable VIP_URL
VIP_URL = os.environ.get("VIP_URL", "http://10.0.0.100:8000/")

# Number of benchmark requests to generate
NUM_REQUESTS = int(os.environ.get("NUM_REQUESTS", "50"))

# Number of warm-up requests before recording data
WARMUP_REQUESTS = int(os.environ.get("WARMUP_REQUESTS", "3"))

# Determine whether sudo is needed
def sudo_prefix() -> list[str]:

    # If already running as root user
    # no need to prepend sudo
    if os.geteuid() == 0:
        return []

    # Otherwise use sudo
    return ["sudo", "-S"]

# Execute shell command
def run_cmd(cmd: list[str]) -> str:

    # subprocess settings
    kwargs = {"text": True}

    # If command uses sudo,
    # automatically provide password from environment variable
    if cmd[:2] == ["sudo", "-S"]:
        kwargs["input"] = os.environ.get("SUDO_PASSWORD", "") + "\n"

    # Execute command and return output
    return subprocess.check_output(cmd, **kwargs).strip()

# Find Mininet h1 Host Process
def find_h1_pid() -> str:

    # Search Linux process table for Mininet host h1
    cmd = (
        r"ps -eo pid,cmd | grep 'mininet:h1' "
        r"| grep -v grep | head -n1 | awk '{print $1}'"
    )

    # Run command
    result = subprocess.check_output(
        cmd,
        shell=True,
        text=True
    ).strip()

    # Error if h1 cannot be found
    if not result:
        raise RuntimeError(
            "Could not find h1 PID. Is Mininet running?"
        )

    return result

# Send HTTP Request from h1
def curl_from_h1(h1_pid: str) -> float:

    # Execute curl inside Mininet host h1 namespace
    cmd = sudo_prefix() + [
        "mnexec",
        "-a",
        h1_pid,

        # HTTP request using curl
        "curl",

        # Disable keepalive connections
        "--no-keepalive",

        # Silent mode
        "-s",

        # Discard downloaded content
        "-o",
        "/dev/null",

        # Print total request latency only
        "-w",
        "%{time_total}",

        # Target VIP URL
        VIP_URL
    ]

    # Execute command
    out = run_cmd(cmd)

    # Convert latency string to float
    return float(out)

# Read Latest Load Balancer Decisio
def latest_decision():

    # Return None if decisions.csv does not exist
    if not DECISIONS_CSV.exists():
        return None

    # Read all rows from CSV
    with DECISIONS_CSV.open("r", newline="") as f:
        rows = list(csv.DictReader(f))

        # Return None if CSV is empty
        if not rows:
            return None

        # Return newest decision
        return rows[-1]

# Generate Unique Decision Identifier
def decision_key(decision: dict | None):

    # Return None if no decision
    if not decision:
        return None

    # Create tuple uniquely identifying a decision
    return (
        decision.get("timestamp"),
        decision.get("client_ip"),
        decision.get("client_tcp_src"),
        decision.get("backend_ip"),
    )

# Initialize dataset.csv
def init_dataset():

    # Create dataset.csv only if it does not exist
    if not DATASET_CSV.exists():

        with DATASET_CSV.open("w", newline="") as f:

            writer = csv.writer(f)

            # Write CSV header row
            writer.writerow([

                # Backend/server information
                "backend_index",
                "tx_rate_bps",
                "rx_rate_bps",
                "drop_delta",
                "active_flows_assigned",

                # Global network statistics
                "total_tx_rate_bps",
                "total_rx_rate_bps",
                "total_active_flows",

                # Relative backend utilization
                "tx_share",
                "rx_share",
                "active_flow_share",

                # Imbalance metrics
                "tx_imbalance_bps",
                "rx_imbalance_bps",
                "flow_imbalance",

                # Measured latency
                "latency_sec",

                # Metadata
                "backend_ip",
                "policy",
            ])

# Append One Training Sample to Dataset
def append_dataset_row(
    decision: dict,
    latency_sec: float
):

    # Open dataset in append mode
    with DATASET_CSV.open("a", newline="") as f:

        writer = csv.writer(f)

        # Write one ML training row
        writer.writerow([

            # Convert fields to appropriate data types
            int(decision["backend_index"]),
            float(decision["tx_rate_bps"]),
            float(decision["rx_rate_bps"]),
            float(decision["drop_delta"]),
            int(decision["active_flows_assigned"]),

            float(decision["total_tx_rate_bps"]),
            float(decision["total_rx_rate_bps"]),
            int(decision["total_active_flows"]),

            float(decision["tx_share"]),
            float(decision["rx_share"]),
            float(decision["active_flow_share"]),

            float(decision["tx_imbalance_bps"]),
            float(decision["rx_imbalance_bps"]),
            float(decision["flow_imbalance"]),

            # Measured request latency
            latency_sec,

            # Backend/server metadata
            decision["backend_ip"],
            decision["policy"],
        ])

# Main Program
def main():

    # Ensure decisions.csv exists
    if not DECISIONS_CSV.exists():
        raise RuntimeError(
            "decisions.csv not found. Start ml_lb.py first."
        )

    # Create dataset.csv if needed
    init_dataset()

    # Find Mininet h1 process ID
    h1_pid = find_h1_pid()

    print(f"Using h1 PID: {h1_pid}")

    # Warm-Up Phase
    # Send several requests before measurement
    # to stabilize connections and caches
    print("Warm-up requests...")

    for _ in range(WARMUP_REQUESTS):

        try:
            _ = curl_from_h1(h1_pid)

        except Exception:
            pass

        time.sleep(0.2)

    # Benchmark Collection Phase
    print("Collecting dataset...")

    for i in range(1, NUM_REQUESTS + 1):

        # Read decision before sending request
        decision_before = latest_decision()
        before_key = decision_key(decision_before)
        
        # Send HTTP request through SDN load balancer
        try:
            latency_sec = curl_from_h1(h1_pid)

        except Exception as exc:

            print(f"[{i}/{NUM_REQUESTS}] failed: {exc}")

            time.sleep(0.2)
            continue

        # Wait briefly for controller to update decisions.csv
        time.sleep(0.1)

        # Read newest decision after request
        decision_after = latest_decision()
        after_key = decision_key(decision_after)

        # If controller logged a new decision,
        # use it. Otherwise use previous one.
        decision = (
            decision_after
            if after_key != before_key
            else decision_before
        )

        # Skip if no decision available
        if decision is None:

            print(
                f"[{i}/{NUM_REQUESTS}] skipped: "
                f"no decision logged yet"
            )

            time.sleep(0.2)
            continue

        # Save one ML training sample
        append_dataset_row(
            decision,
            latency_sec
        )

        # Print benchmark result
        print(
            f"[{i}/{NUM_REQUESTS}] "
            f"backend={decision['backend_ip']} "
            f"policy={decision['policy']} "
            f"latency={latency_sec:.6f}s"
        )

        # Small delay between requests
        time.sleep(0.2)

    # Finished
    print(f"Done. Dataset saved to {DATASET_CSV}")


if __name__ == "__main__":
    main()
